from collections import Counter
cats = Counter(c['category'] for c in cases)
print(f"TOTAL: {len(cases)} cases, {len(cats)} categories")
for cat, count in cats.most_common():
    print(f"  {cat}: {count}")
ev = sum(1 for c in cases if c.get('evidence'))
print(f"\nEvidence: {ev}/{len(cases)} ({ev*100//len(cases)}%)")
print(f"\n{'='*40}")
print(f"200+ TARGET: {'✅ HIT!' if len(cases) >= 200 else f'❌ {200-len(cases)} more needed'}")
